import{_ as s,o as t,c as n,O as l}from"./chunks/framework.1e3ff9a3.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{"aside":false,"outline":false,"lastUpdated":false},"headers":[],"relativePath":"materials/pitch.md","filePath":"materials/pitch.md","lastUpdated":1775707265000}'),d={name:"materials/pitch.md"};function r(p,a,i,e,c,_){return t(),n("div",null,a[0]||(a[0]=[l('<div class="brand-page-shell"><section class="brand-hero"><div><p class="brand-kicker">Pitch Outline</p><h1>对外介绍提纲</h1><div class="brand-hero__panel"><span class="brand-pill">Talking Point</span><strong>真正有效的介绍，不是讲很多技术名词，而是让听的人快速知道它是什么、解决什么问题、为什么现在值得继续听。</strong><p>这页就是按这个逻辑展开的。</p></div><p class="brand-lead"> 这一页把 SmartFlow 的对外介绍收成可直接复用的提纲。 你可以把它当成官网讲稿、路演草稿、初次沟通提纲，或者 10 页 PPT 的骨架。 </p><div class="brand-chip-list"><span class="brand-chip">30 秒版本</span><span class="brand-chip">3 分钟版本</span><span class="brand-chip">10 页结构</span><span class="brand-chip">公开安全</span></div><div class="brand-actions"><a class="cta-button cta-button--brand" href="./value.html">看价值说明</a><a class="cta-button" href="../product/index.html">看产品概览</a></div></div><div class="brand-hero__media brand-hero__media--compact"><div class="matrix-panel matrix-panel--contact"><div class="matrix-panel__hud"><span>SMARTFLOW // PITCH OUTLINE</span><span>MAT 02</span></div><div class="matrix-panel__canvas"><div class="matrix-panel__trace matrix-panel__trace--top"></div><div class="matrix-panel__trace matrix-panel__trace--mid"></div><div class="matrix-panel__trace matrix-panel__trace--bottom"></div><div class="matrix-panel__stack"><span class="matrix-panel__line"><span class="matrix-panel__key">problem</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">scripts exist</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value">entry does not</span></span><span class="matrix-panel__line"><span class="matrix-panel__key">platform</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">ai judge</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value">controlled execution</span></span><span class="matrix-panel__line"><span class="matrix-panel__key">delivery</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">tenant</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value">url</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value">update</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value">isolation</span></span></div><div class="matrix-panel__callout">A GOOD INTRO SHOULD REDUCE CONFUSION, NOT ADD BUZZWORDS</div></div><div class="matrix-panel__footer"><span class="matrix-panel__tag"><span class="matrix-panel__key">pitch</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">short</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">pitch</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">medium</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">pitch</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">deck</span></span></div></div></div></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">30 Seconds</p><h2>30 秒版本怎么讲</h2><p>SmartFlow 不是普通聊天系统，而是一套让 AI 在规则内调用真实脚本和流程的智能执行平台。它把分散在文件夹、服务器和个人经验里的能力，收成一个可控、可交付、可持续更新的统一入口。</p></article><article class="brand-card"><p class="brand-kicker">3 Minutes</p><h2>3 分钟版本怎么讲</h2><p>先讲问题：很多企业已经有脚本和流程，但没有统一执行入口。再讲平台：AI 负责理解需求和推荐能力，平台负责边界、确认、执行和审计。最后讲价值：一个客户一个租户，一个客户一个网址，后续脚本还能持续热更新。</p></article></section><section class="brand-card"><p class="brand-kicker">Deck Structure</p><h2>10 页结构可以怎么排</h2><table><thead><tr><th>页次</th><th>标题</th><th>这一页要讲清什么</th><th>建议画面</th></tr></thead><tbody><tr><td>01</td><td>封面页</td><td>讲清平台名字和一句话定位</td><td>平台主视觉 + 口号</td></tr><tr><td>02</td><td>我们在解决什么问题</td><td>很多企业已有脚本和流程，但没有统一执行入口</td><td>分散脚本汇入一个平台入口</td></tr><tr><td>03</td><td>平台是什么</td><td>不是普通聊天系统，而是可信执行平台</td><td>上层对话、下层脚本与权限的分层图</td></tr><tr><td>04</td><td>核心交付模式</td><td>一个客户一个租户，一个客户一个网址</td><td>多客户对应多个独立租户</td></tr><tr><td>05</td><td>为什么客户愿意买单</td><td>客户买的不是页面，而是效率、隔离和可持续更新</td><td>人工操作 vs 平台执行对比图</td></tr><tr><td>06</td><td>平台内部闭环</td><td>用户需求 -&gt; AI 理解 -&gt; 推荐能力 -&gt; 确认 -&gt; 执行 -&gt; 结果</td><td>横向流程图</td></tr><tr><td>07</td><td>当前落地能力</td><td>多租户、脚本注册、智能大脑、热更新、CLI 已有真实基础</td><td>能力卡片墙</td></tr><tr><td>08</td><td>安全与隔离优势</td><td>平台强项不是更会说，而是只能在授权范围内做事</td><td>租户、权限、确认、审计边界图</td></tr><tr><td>09</td><td>商业路径</td><td>1.0 交付，2.0 产品化，3.0 生态化，4.0 基础设施化</td><td>版本路线图</td></tr><tr><td>10</td><td>结尾页</td><td>收束成一句明确价值表达</td><td>主视觉 + 联系方式</td></tr></tbody></table></section><section class="brand-grid brand-grid--three"><article class="brand-card"><p class="brand-kicker">Do Say</p><h2>建议这样讲</h2><ul class="brand-list"><li>它把分散脚本收进统一入口</li><li>AI 在规则内推荐和触发能力</li><li>平台强调租户隔离、确认执行和审计留痕</li><li>一个客户一个租户，一个客户一个网址</li></ul></article><article class="brand-card"><p class="brand-kicker">Do Not Say</p><h2>不建议这样讲</h2><ul class="brand-list"><li>不要把它讲成普通聊天工具</li><li>不要把 Agent 骨架讲成已经成熟的本地执行产品</li><li>不要把团队版讲成已经完全标准化开放</li><li>不要把内部部署、内部台账和内部报价混进公开资料</li></ul></article><article class="brand-card"><p class="brand-kicker">Demo Order</p><h2>如果要演示，顺序建议</h2><ol class="brand-list"><li>先讲问题和平台定义</li><li>再展示产品概览或体验路径</li><li>再讲客户流程 / 交付和隔离边界</li><li>最后按需要补 CLI 或部署方式</li></ol></article></section><section class="brand-card brand-card--cta"><div class="brand-card__row"><div><p class="brand-kicker">Next Read</p><h2>如果你要继续把“价值”讲得更清楚</h2><p class="brand-lead">建议再看一页价值说明，把老板、业务负责人和交付负责人最关心的问题一起收口。</p></div><div class="brand-link-grid brand-link-grid--compact"><a class="brand-link-card" href="./value.html"><span>Value</span><strong>价值说明</strong></a><a class="brand-link-card" href="../product/customer-flow.html"><span>Delivery</span><strong>客户流程 / 交付</strong></a><a class="brand-link-card" href="../product/editions.html"><span>Roadmap</span><strong>版本路线</strong></a><a class="brand-link-card" href="../contact.html#lead-form"><span>Lead</span><strong>联系我</strong></a></div></div></section></div>',1)]))}const h=s(d,[["render",r]]);export{m as __pageData,h as default};
